// Filtrar partidos dentro de la ventana de 48 horas
const events = $input.all();
const now = new Date();
const windowHours = 48;
const windowMs = windowHours * 60 * 60 * 1000;

const upcomingEvents = events.filter(item => {
  const startsAt = new Date(item.json.starts_at);
  const diffMs = startsAt - now;
  // Entre 0 y 48 horas desde ahora
  return diffMs > 0 && diffMs <= windowMs;
});

if (upcomingEvents.length === 0) {
  // No hay partidos próximos, detener el flujo
  return [];
}

console.log(`Partidos encontrados en ventana 48h: ${upcomingEvents.length}`);
return upcomingEvents.map(e => ({ json: e.json }));

// Crear el producto cartesiano: cada negocio × cada partido próximo
// Pero evitar duplicados: si ya existe un envío previo para este par (negocio+partido), saltar
const events = $('Filtrar Ventana 48 Horas').all().map(i => i.json);
const businesses = $input.all().map(i => i.json);

const pairs = [];

for (const event of events) {
  for (const biz of businesses) {
    pairs.push({
      json: {
        event_id: event.id,
        event_home_team: event.home_team,
        event_away_team: event.away_team,
        event_league: event.league || 'Copa Mundial FIFA 2026',
        event_starts_at: event.starts_at,
        event_venue: event.venue || '',
        event_home_logo: event.home_team_logo || '',
        event_away_logo: event.away_team_logo || '',
        event_metadata: event.event_metadata || {},
        business_id: biz.id,
        business_name: biz.business_name,
        business_type: biz.business_type,
        neighborhood: biz.neighborhood,
        city: biz.city,
        whatsapp: biz.whatsapp,
        instagram: biz.instagram || '',
        // Digital Identity Layer
        target_audience: biz.target_audience || [],
        communication_tone: biz.communication_tone || '',
        specialties: biz.specialties || [],
        usual_promos: biz.usual_promos || [],
        preferred_hashtags: biz.preferred_hashtags || [],
        preferred_language: biz.preferred_language || 'Español',
        // Tono basado en tipo de negocio o valor explícito
        tone: biz.communication_tone || (['Gastrobar', 'Discoteca'].includes(biz.business_type) ? 'premium' : 'paisa')
      }
    });
  }
}

console.log(`Pares negocio×partido generados: ${pairs.length}`);
return pairs;

// Construir el prompt para Gemini con contexto del partido y del negocio
const pair = $('Cruzar Negocios × Partidos').item.json;

const fechaPartido = new Date(pair.event_starts_at).toLocaleDateString('es-CO', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  timeZone: 'America/Bogota'
});

// Extraer metadata del partido (Tiers, Focus, etc)
const meta = pair.event_metadata || {};
const focus = meta.narrative_focus || '';
const rivalry = meta.rivalry_context || '';
let playersText = '';
if (meta.key_players) {
  let playersArr = typeof meta.key_players === 'string' ? JSON.parse(meta.key_players) : meta.key_players;
  if (Array.isArray(playersArr) && playersArr.length > 0) {
    playersText = `Jugadores clave a mencionar: ${playersArr.join(', ')}. `;
  }
}

// Determinar si Colombia juega
const colombiaJuega = pair.event_home_team.toLowerCase().includes('colombia') || 
                      pair.event_away_team.toLowerCase().includes('colombia');

const rival = pair.event_home_team.toLowerCase().includes('colombia') 
  ? pair.event_away_team 
  : pair.event_home_team;

// Digital Identity Context
const audienceText = pair.target_audience && pair.target_audience.length > 0 ? ` Tu público objetivo principal es: ${pair.target_audience.join(', ')}.` : '';
const specialtiesText = pair.specialties && pair.specialties.length > 0 ? ` Las especialidades del local son: ${pair.specialties.join(', ')}. Menciona esto en al menos uno de los posts.` : '';
const promosText = pair.usual_promos && pair.usual_promos.length > 0 ? ` Sugiere alguna promoción similar a estas que solemos ofrecer: ${pair.usual_promos.join(', ')}.` : '';
const hashtagsText = pair.preferred_hashtags && pair.preferred_hashtags.length > 0 ? ` Incluye obligatoriamente estos hashtags al final: ${pair.preferred_hashtags.join(', ')}.` : '';

// System Prompt (Tono e Identidad)
let systemPrompt = `Eres un experto redactor de marketing deportivo. Escribes en ${pair.preferred_language || 'Español'}. Representas a un establecimiento llamado "${pair.business_name}" (Tipo: ${pair.business_type}) en ${pair.city}.${audienceText}`;

if (pair.tone === 'premium') {
  systemPrompt += ' Escribe con un tono elegante, neutro y premium. Usa emojis moderados.';
} else if (pair.tone === 'paisa') {
  systemPrompt += ' Escribe con energía y jerga paisa auténtica de Medellín (parce, mon, ¡arriba!). Usa emojis con energía.';
} else {
  systemPrompt += ` Tu tono de comunicación específico debe ser: ${pair.tone}.`;
}
systemPrompt += ' Tu objetivo principal es redactar captions cortos de Instagram (max 300 caracteres cada uno) para atraer público al local a ver el partido.';

// User Prompt (Partido y Ángulos)
let userPrompt = colombiaJuega
  ? `Crea 3 publicaciones DIFERENTES para Instagram (caption únicamente) para el negocio "${pair.business_name}" en ${pair.neighborhood}. El partido es: COLOMBIA 🇨🇴 vs ${rival}. Fecha: ${fechaPartido}. Liga: ${pair.event_league}. `
  : `Crea 3 publicaciones DIFERENTES para Instagram (caption únicamente) para el negocio "${pair.business_name}" en ${pair.neighborhood}. Transmitirán el partido: ${pair.event_home_team} vs ${pair.event_away_team}. Fecha: ${fechaPartido}. Liga: ${pair.event_league}. `;

// Inyectar narrativa del partido
if (focus) userPrompt += `\nEnfoque narrativo sugerido del partido: "${focus}". `;
if (rivalry) userPrompt += `Contexto de rivalidad: "${rivalry}". `;
if (playersText) userPrompt += playersText;

// Inyectar identidad del negocio
userPrompt += `\n\nContexto del local: ${specialtiesText} ${promosText}`;

userPrompt += `\n\nCada publicación debe tener un ángulo diferente:\n1) Convocatoria a ver el partido / Emoción.\n2) Ambiente y experiencia en el local (mencionando especialidades).\n3) Urgencia o promoción especial para el partido.\n\nSepara cada publicación estrictamente con ---SEPARADOR---. ${hashtagsText}`;

return {
  json: {
    ...pair,
    fecha_partido_formateada: fechaPartido,
    colombia_juega: colombiaJuega,
    rival: rival,
    system_prompt: systemPrompt,
    user_prompt: userPrompt
  }
};

// Parsear las 3 variantes generadas por Gemini
const rawText = $input.first().json.text;
const pair = $('Construir Prompt Contextual').item.json;

// Separar las 3 variantes
const variantes = rawText
  .split('---SEPARADOR---')
  .map(v => v.trim())
  .filter(v => v.length > 0)
  .slice(0, 3);

// Si Gemini no usó el separador correctamente, dividir equitativamente
const contenidos = variantes.length >= 2 ? variantes : [rawText];

// Formatear la fecha legible para el mensaje de WhatsApp
const fechaPartido = pair.fecha_partido_formateada;
const emoji = pair.colombia_juega ? '🇨🇴⚽' : '⚽';

// Construir el mensaje completo de WhatsApp
let mensajeWA = `${emoji} *¡Contenido listo para ${pair.business_name}!*\n\n`;
mensajeWA += `*Partido:* ${pair.event_home_team} vs ${pair.event_away_team}\n`;
mensajeWA += `*Cuándo:* ${fechaPartido}\n`;
mensajeWA += `*Liga:* ${pair.event_league}\n\n`;
mensajeWA += `Aquí tienes *3 opciones de caption* para tu Instagram. Elige la que más te guste, agrega una foto del ambiente de tu local y ¡publica! 👇\n\n`;
mensajeWA += `━━━━━━━━━━━━━━━━━━━━\n`;

contenidos.forEach((c, i) => {
  mensajeWA += `\n*Opción ${i + 1}:*\n${c}\n\n`;
  if (i < contenidos.length - 1) mensajeWA += `━━━━━━━━━━━━━━━━━━━━\n`;
});

mensajeWA += `\n━━━━━━━━━━━━━━━━━━━━\n`;
mensajeWA += `_FanFest AI 🤖 — Copiá, personalizá y publicá. ¡Nos cuentas cómo te fue después del partido!_`;

return {
  json: {
    business_id: pair.business_id,
    event_id: pair.event_id,
    whatsapp: pair.whatsapp,
    business_name: pair.business_name,
    mensaje_wa: mensajeWA,
    contenidos_generados: contenidos,
    raw_response: rawText,
    system_prompt_used: pair.system_prompt,
    user_prompt_used: pair.user_prompt
  }
};
